```typescript
// MCP Server đơn giản với Node.js
import { Server } from '@modelcontextprotocol/sdk/server/index.js';
import { StdioServerTransport } from '@modelcontextprotocol/sdk/server/stdio.js';

const server = new Server({
  name: 'my-db-tools',
  version: '1.0.0',
}, {
  capabilities: { tools: {} }
});

// Expose tool cho AI
server.setRequestHandler(ListToolsRequestSchema, async () => ({
  tools: [{
    name: 'query_orders',
    description: 'Query orders từ PostgreSQL với filter',
    inputSchema: {
      type: 'object',
      properties: {
        status: { type: 'string', enum: ['pending', 'completed'] },
        limit: { type: 'number', default: 10 }
      }
    }
  }]
}));

// Handle tool call
server.setRequestHandler(CallToolRequestSchema, async (req) => {
  if (req.params.name === 'query_orders') {
    const rows = await db.query(
      'SELECT * FROM orders WHERE status=$1 LIMIT $2',
      [req.params.arguments.status, req.params.arguments.limit]
    );
    return { content: [{ type: 'text', text: JSON.stringify(rows) }] };
  }
});

await server.connect(new StdioServerTransport());
